SELECT FROM rbac_rolepermission RP INNER JOIN rbac_menuoperate MO ON RP.MENUOPERATE_ID = MO.ID INNER JOIN rbac_menuinfo MI ON MO.MENUINFO_ID = MI.ID
ROLE_ID = #{roleId}
union SELECT FROM rbac_flow_permission FP JOIN rbac_menuoperate MO ON FP.ACTIVITY_CODE = MO.CODE AND FP.FLOW_KEY = MO.FLOW_KEY INNER JOIN rbac_menuinfo MI ON MO.MENUINFO_ID = MI.ID
FP.FLOW_PERMISSION_TYPE = 'ROLE' AND FP.TYPE_ID = #{roleId}
